import{_ as t,o as i,c as a,a2 as n}from"./chunks/framework.y1bVONfd.js";const g=JSON.parse('{"title":"AI Generation","description":"","frontmatter":{},"headers":[],"relativePath":"builder/ai-generation.md","filePath":"builder/ai-generation.md"}'),s={name:"builder/ai-generation.md"};function o(l,e,r,p,d,h){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="ai-generation" tabindex="-1">AI Generation <a class="header-anchor" href="#ai-generation" aria-label="Permalink to &quot;AI Generation&quot;">​</a></h1><p>WebBeagle integrates AI for generating page sections, refining elements, and redesigning with vision comparison.</p><h2 id="ai-panel-🤖-ai" tabindex="-1">AI Panel (🤖 AI) <a class="header-anchor" href="#ai-panel-🤖-ai" aria-label="Permalink to &quot;AI Panel (🤖 AI)&quot;">​</a></h2><p>Click the <strong>🤖 AI</strong> button in the toolbar to open the AI panel.</p><h3 id="text-to-section-generation" tabindex="-1">Text-to-Section Generation <a class="header-anchor" href="#text-to-section-generation" aria-label="Permalink to &quot;Text-to-Section Generation&quot;">​</a></h3><ol><li>Type a description of what you want</li><li>Click <strong>Generate</strong></li><li>The section appears in the current page</li></ol><p><strong>Example prompts:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Add a pricing table with 3 tiers: Starter ($29/mo), Pro ($79/mo), Enterprise ($199/mo)</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Create a team section with 4 member cards — photos, names, roles, and short bios</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Add a FAQ section with 5 questions about managed WordPress hosting</span></span></code></pre></div><h3 id="ai-with-design-image" tabindex="-1">AI with Design Image <a class="header-anchor" href="#ai-with-design-image" aria-label="Permalink to &quot;AI with Design Image&quot;">​</a></h3><ol><li>Upload a screenshot or design mockup</li><li>Type instructions: &quot;Recreate this pricing table in our style&quot;</li><li>AI uses vision to match the design, then applies WebBeagle theming</li></ol><h2 id="element-refinement" tabindex="-1">Element Refinement <a class="header-anchor" href="#element-refinement" aria-label="Permalink to &quot;Element Refinement&quot;">​</a></h2><p>Close the &quot;80% → pixel perfect&quot; gap with targeted AI refinements:</p><ol><li>Select any element on the canvas</li><li>Open the AI panel</li><li>Upload a reference image (showing what it should look like)</li><li>Type an instruction: &quot;Add green outer glow to this text&quot;</li><li>AI returns only the CSS delta needed</li></ol><p><strong>Best for:</strong></p><ul><li>Text treatments (gloss, glow, shadows)</li><li>Spacing and alignment tweaks</li><li>Color adjustments</li><li>Border and shadow refinements</li></ul><h2 id="ai-onboarding-new-projects" tabindex="-1">AI Onboarding (New Projects) <a class="header-anchor" href="#ai-onboarding-new-projects" aria-label="Permalink to &quot;AI Onboarding (New Projects)&quot;">​</a></h2><ol><li>Click <strong>🧪 Onboard AI</strong> in the toolbar</li><li>Fill out the wizard: <ul><li>Project name</li><li>Industry (e.g., &quot;fitness tracking&quot;)</li><li>Brand voice (e.g., &quot;gritty, motivational, premium&quot;)</li><li>Font preferences</li><li>Color palette (type hex codes)</li><li>Upload design screenshots (optional)</li><li>Scrape competitor URLs (optional)</li></ul></li><li>Click <strong>Generate Full Site</strong></li><li>AI builds a complete homepage with all blocks, themed to your brand</li></ol><h2 id="ai-qa-dogfooding" tabindex="-1">AI QA / Dogfooding <a class="header-anchor" href="#ai-qa-dogfooding" aria-label="Permalink to &quot;AI QA / Dogfooding&quot;">​</a></h2><p>For testing published pages, use the browser tools:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://slug.preview.webbeagle.com/&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;!DOCTYPE&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> wc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Should return 1 — nested HTML means broken CSS</span></span></code></pre></div><p>Common AI-generation pitfalls:</p><ul><li>Saving full HTML documents as components creates nested <code>&lt;html&gt;</code> — save only <code>&lt;style&gt;</code> + <code>&lt;section&gt;</code></li><li>Buttons mapped incorrectly — &quot;primary button&quot; → <code>.btn-primary</code> with <code>&lt;span&gt;</code>, &quot;secondary&quot; → <code>.btn-secondary</code></li></ul><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>AI requests are processed by the Flask backend:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Builder → POST /api/ai/generate → Flask → AI model → Returns HTML → Inserted into canvas</span></span></code></pre></div><p>The AI prompt includes:</p><ul><li>Current theme CSS (so generated sections match)</li><li>Brand guidelines (colors, fonts, mascot)</li><li>Button type mapping (primary/secondary)</li><li>Component structure conventions</li></ul>`,29)])])}const u=t(s,[["render",o]]);export{g as __pageData,u as default};
